formulas.expression:
IF(
   AND(
           ISBLANK({!OBSOwnerFromAccount}),
           NOT(ISPICKVAL({!Opportunity.Onboarding_Path__c},'Self Serve'))
      ),
         '00G3u000002egpzEAA',
    IF(
         ISPICKVAL({!Opportunity.Onboarding_Path__c},'Self Serve'),
         '00G3u000002aqp3EAA',
         {!OBSOwnerFromAccount}
      )
)

IF(
  OR(
    AND(
      NOT(ISBLANK({!Get_School_Object.Billing_Adding_Payers_Stage_Met_Date__c})),
      DATEVALUE({!Get_School_Object.Billing_Adding_Payers_Stage_Met_Date__c}) < {!Opportunity.CloseDate}
    ),
    AND(
      NOT(ISBLANK({!Get_School_Object.Billing_Adding_Students_Stage_Met_Date__c})),
      DATEVALUE({!Get_School_Object.Billing_Adding_Students_Stage_Met_Date__c}) < {!Opportunity.CloseDate}
    ),
    AND(
      NOT(ISBLANK({!Get_School_Object.Billing_Complete_Set_Up_Stage_Met_Date__c})),
      DATEVALUE({!Get_School_Object.Billing_Complete_Set_Up_Stage_Met_Date__c}) < {!Opportunity.CloseDate}
    ),
    AND(
      NOT(ISBLANK({!Get_School_Object.Billing_Online_Payments_Stage_Met_Date__c})),
      DATEVALUE({!Get_School_Object.Billing_Online_Payments_Stage_Met_Date__c}) < {!Opportunity.CloseDate}
    ),
    AND(
      NOT(ISBLANK({!Get_School_Object.Billing_Sending_Bills_Stage_Met_Date__c})),
      DATEVALUE({!Get_School_Object.Billing_Sending_Bills_Stage_Met_Date__c}) < {!Opportunity.CloseDate}
    ),
    AND(
      NOT(ISBLANK({!Get_School_Object.Billing_Submit_Verify_Stage_Met_Date__c})),
      DATEVALUE({!Get_School_Object.Billing_Submit_Verify_Stage_Met_Date__c}) < {!Opportunity.CloseDate}
    ),
    AND(
      NOT(ISBLANK({!Get_School_Object.Billing_FinalVerification_Stage_Met_Date__c})),
      DATEVALUE({!Get_School_Object.Billing_FinalVerification_Stage_Met_Date__c}) < {!Opportunity.CloseDate}
    ),
    AND(
      NOT(ISBLANK({!Get_School_Object.Billing_Setting_Up_Bills_Stage_Met_Date__c})),
      DATEVALUE({!Get_School_Object.Billing_Setting_Up_Bills_Stage_Met_Date__c}) < {!Opportunity.CloseDate}
    )
  ),
  TRUE,
  FALSE
)
